import math
from pathlib import Path

import pytest
import yaml

from astar import a_star

FIXTURES_DIR = Path(__file__).parent / 'fixtures'


def _load_fixture(path):
    with open(path) as f:
        return yaml.safe_load(f)


def _heuristic_from(mapping):
    return lambda node: mapping[node]


def _path_cost(graph, path):
    return sum(graph[u][v] for u, v in zip(path, path[1:]))


@pytest.fixture(
    params=sorted(FIXTURES_DIR.glob('*.yaml')),
    ids=lambda p: p.stem,
)
def fixture(request):
    return _load_fixture(request.param)


def _run(fixture):
    return a_star(
        fixture['graph'],
        fixture['start'],
        fixture['goal'],
        _heuristic_from(fixture['heuristic']),
    )


def test_length_matches_expected(fixture):
    _, length = _run(fixture)
    assert length == fixture['expected_length']


def test_path_matches_expected(fixture):
    path, _ = _run(fixture)
    assert path == fixture['expected_path']


def test_path_cost_equals_returned_length(fixture):
    path, length = _run(fixture)
    if not path:
        assert length == math.inf
    else:
        assert _path_cost(fixture['graph'], path) == length


def test_path_endpoints(fixture):
    path, _ = _run(fixture)
    if not path:
        return
    assert path[0] == fixture['start']
    assert path[-1] == fixture['goal']

